// Captura a resposta bruta da Gemini
let resposta = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || "";

// ----------------------------
// DADOS DO ENVIO
// ----------------------------
const nomeEnvio = $('ENVIO').first().json.name || "";

let posto = null;
let data = null;

// FORMATO: RELATÓRIO ENVIO P76 DIA 04.05.2026.pdf
const match = nomeEnvio.match(/P(\d+)\s+DIA\s+(\d{2})[./-](\d{2})[./-](\d{4})/i);

if (match) {
  posto = match[1];
  data = `${match[2]}/${match[3]}/${match[4]}`;
}

// ----------------------------
// NORMALIZA RESPOSTA
// ----------------------------
resposta = String(resposta)
  .trim()
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// ---------------------------------------------------
// Função para extrair JSON array
// ---------------------------------------------------
function extrairJsonArray(texto) {
  const start = texto.indexOf("[");
  const end = texto.lastIndexOf("]");

  if (start !== -1 && end !== -1 && end > start) {
    return texto.substring(start, end + 1);
  }

  return null;
}

const jsonBruto = extrairJsonArray(resposta);

if (!jsonBruto) {
  return [{
    json: {
      sucesso: false,
      erro: "❌ Nenhum array JSON encontrado na resposta",
      respostaBruta: resposta,
      posto,
      data
    }
  }];
}

try {
  const parsed = JSON.parse(jsonBruto);

  if (!Array.isArray(parsed)) {
    return [{
      json: {
        sucesso: false,
        erro: "❌ O JSON retornado não é um array no formato esperado",
        jsonExtraido: jsonBruto,
        respostaBruta: resposta,
        posto,
        data
      }
    }];
  }

  if (parsed.length === 0) {
    return [{
      json: {
        sucesso: true,
        mensagem: "Nenhum paciente encontrado",
        pacientes: [],
        _totalPacientes: 0,
        posto,
        data
      }
    }];
  }

  return parsed.map((paciente, idx) => {
    const exames = Array.isArray(paciente.EXAMES)
      ? paciente.EXAMES
      : [];

    let valor = paciente.VALOR ?? null;

    if (typeof valor === "string") {
      valor = valor
        .replace(/[R$\s]/g, "")
        .replace(/\./g, "")
        .replace(",", ".");

      valor = valor === "" ? null : Number(valor);
    }

    return {
      json: {
        sucesso: true,
        categoria: "(+)COMPUTADOR DO POSTO",

        PACIENTE: paciente.PACIENTE ?? null,
        EXAMES: exames,
        EXAMES_TEXTO: exames.join(", "),
        QTD_EXAMES: exames.length,
        VALOR: valor,

        posto,
        data,

        _idx: idx + 1,
        _totalPacientes: parsed.length
      }
    };
  });

} catch (e) {
  return [{
    json: {
      sucesso: false,
      erro: "❌ JSON encontrado, mas inválido",
      mensagem: e.message,
      jsonExtraido: jsonBruto,
      respostaBruta: resposta,
      posto,
      data
    }
  }];
}

// =======================================================
// OCR -> Prompt | Protocolo de Envio ao Laboratório
// Entrada esperada: $input.first().json.extractedText
// Saída: prompt pronto para enviar para a IA
// =======================================================

const item = $input.first();
const conteudoBruto = item?.json?.extractedText || "";

// -------------------------
// 1) Normalização base
// -------------------------
let texto = String(conteudoBruto)
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")
  .replace(/"/g, "'")
  .replace(/[\u0000-\u001F\u007F-\u009F]/g, " ")
  .replace(/\t/g, " ")
  .replace(/[ ]{2,}/g, " ")
  .replace(/\n[ ]+/g, "\n")
  .replace(/[ ]+\n/g, "\n")
  .trim();

// -------------------------
// 2) Limpeza leve para OCR
// -------------------------
function normalizarOcr(s) {
  let t = s;

  t = t.replace(/Protocolo\s+de\s+Envio\s+ao\s+Laborat[oó]rio/gi, "Protocolo de Envio ao Laboratório");
  t = t.replace(/Paciente/gi, "Paciente");
  t = t.replace(/Exames/gi, "Exames");
  t = t.replace(/Valor/gi, "Valor");

  t = t.replace(/[ ]{2,}/g, " ").trim();

  return t;
}

const conteudoLimpo = normalizarOcr(texto);

// -------------------------
// 3) Nome do arquivo, se existir
// -------------------------
const nomeArquivo =
  item?.json?.arquivo ||
  item?.json?.nome ||
  item?.json?.fileName ||
  "sem_nome.pdf";

// -------------------------
// 4) Conteúdo final enviado ao modelo
// -------------------------
const conteudoFinal = `🗂️ Documento: ${nomeArquivo}\n"""${conteudoLimpo}"""`;

// =======================================================
// 5) Prompt
// =======================================================
const prompt = `
Você é um especialista em extração de dados de documentos textuais.

Sua tarefa é analisar o texto OCR fornecido abaixo, identificar a tabela de "Protocolo de Envio ao Laboratório" e extrair as informações de forma estruturada.

RETORNE APENAS JSON VÁLIDO.
Não use markdown.
Não escreva explicações.
Não escreva texto fora do JSON.
Não invente pacientes.
Não duplique pacientes.

FORMATO DE SAÍDA OBRIGATÓRIO:
[
  {
    "PACIENTE": "NOME COMPLETO DO PACIENTE",
    "EXAMES": ["CODIGO1", "CODIGO2"],
    "VALOR": 99.10
  }
]

REGRAS DE EXTRAÇÃO:

1) PACIENTE
- Extraia o nome completo do paciente.
- Preserve o nome em letras maiúsculas, se estiver assim no documento.
- Não confunda nome de paciente com cabeçalho, laboratório, posto, data ou observações.

2) EXAMES
- Extraia todos os códigos de exames do paciente.
- Os exames podem aparecer separados por vírgula.
- Os códigos podem vir acompanhados de valores entre colchetes.
- Ignore tudo que estiver entre colchetes.
- Exemplo:
  "25OHD [20,00], B12 [15,00], TSH [10,00]"
  deve retornar:
  ["25OHD", "B12", "TSH"]

3) VALOR
- Extraia o valor total do paciente na coluna "Valor".
- Retorne como número decimal JSON.
- Se o valor estiver no formato brasileiro, converta:
  "99,10" -> 99.10
  "1.234,56" -> 1234.56

4) INCLUSÃO
- Extraia todos os pacientes presentes na tabela.
- Inclua pacientes mesmo que tenham apenas um exame.
- Se não encontrar pacientes, retorne [].

5) VALIDAÇÃO
- A saída deve ser um array JSON válido.
- Não coloque comentários.
- Não coloque vírgula sobrando.
- Não retorne objeto com chave "dados"; retorne diretamente o array.

AGORA EXTRAIA DO TEXTO ABAIXO:

${conteudoFinal}
`.trim();

// =======================================================
// 6) Retorno para o modelo
// =======================================================
return {
  json: {
    contents: [
      {
        role: "user",
        parts: [
          {
            text: prompt,
          },
        ],
      },
    ],
  },
};

