      jsonExtraido: jsonBruto,
      respostaBruta: resposta
    }
  }];
}

// =======================================================
// OCR -> Prompt | Relatório de Motoqueiros / Exames
// Entrada esperada: $input.first().json.extractedText
// Saída: prompt pronto para enviar para a IA
// =======================================================

const item = $input.first();
const conteudoBruto = item?.json?.extractedText || "";

// -------------------------
// 1) Normalização base
// -------------------------
let texto = String(conteudoBruto)
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")
  .replace(/"/g, "'")
  .replace(/[\u0000-\u001F\u007F-\u009F]/g, " ")
  .replace(/\t/g, " ")
  .replace(/[ ]{2,}/g, " ")
  .replace(/\n[ ]+/g, "\n")
  .replace(/[ ]+\n/g, "\n")
  .trim();

// -------------------------
// 2) Limpeza leve para OCR
// -------------------------
function normalizarOcr(s) {
  return String(s || "")
    .replace(/Relat[oó]rio\s+de\s+Motoqueiros/gi, "Relatório de Motoqueiros")
    .replace(/Paciente/gi, "Paciente")
    .replace(/Exames?/gi, "Exame")
    .replace(/[ ]{2,}/g, " ")
    .trim();
}

const conteudoLimpo = normalizarOcr(texto);

// -------------------------
// 3) Nome do arquivo, se existir
// -------------------------
const nomeArquivo =
  item?.json?.arquivo ||
  item?.json?.nome ||
  item?.json?.fileName ||
  "sem_nome.pdf";

// -------------------------
// 4) Conteúdo final enviado ao modelo
// -------------------------
const conteudoFinal = `🗂️ Documento: ${nomeArquivo}\n"""${conteudoLimpo}"""`;

// =======================================================
// 5) Prompt
// =======================================================
const prompt = `
Você é um especialista em extração de dados de documentos textuais.

Sua tarefa é analisar o texto OCR fornecido abaixo e extrair os dados da tabela de exames.

RETORNE APENAS JSON VÁLIDO.
Não use markdown.
Não escreva explicações.
Não escreva texto fora do JSON.
Não invente pacientes.
Não duplique pacientes.

FORMATO DE SAÍDA OBRIGATÓRIO:
[
  {
    "PACIENTE": "NOME COMPLETO DO PACIENTE",
    "EXAMES": ["EXAME1", "EXAME2"],
    "VALOR": null
  }
]

REGRAS DE EXTRAÇÃO:

1) PACIENTE
- Extraia o nome completo do paciente.
- O nome geralmente está na coluna anterior aos exames.
- Ignore cabeçalhos como LABOVIDA, Relatório, datas, códigos numéricos e linhas de separação.

2) EXAMES
- Os exames aparecem imediatamente após o nome do paciente na mesma linha da tabela.
- A linha geralmente segue este padrão:
  | DATA | CODIGO | PACIENTE | EXAMES |
- Tudo que estiver na coluna após o PACIENTE deve ser tratado como lista de exames.
- Se houver mais de um exame separado por espaço, retorne cada exame separado no array.
- Exemplo:
  | 04/05/2026 | 3568082 | MURILO HENRIQUE GONÇALVES ASFORA | TESTO TTL |
  Resultado:
  "EXAMES": ["TESTO", "TTL"]
- Exemplo:
  | 04/05/2026 | 3568070 | ALINE CARLA SOUZA COSTA DE LIRA | HEMO TGO TGP TRI TTPA |
  Resultado:
  "EXAMES": ["HEMO", "TGO", "TGP", "TRI", "TTPA"]
- Se o exame for composto por várias palavras, mantenha como um único exame somente quando for claramente um nome composto de exame.
  Exemplo:
  "PARASITOLOGICO DE FEZES" deve virar:
  ["PARASITOLOGICO DE FEZES"]
- Não junte exames diferentes.
- Não transforme nem interprete os códigos.
- Não invente exames.

3) VALOR
- Se não existir valor no texto, retorne null.
- Não invente valores.

4) INCLUSÃO
- Extraia todos os pacientes encontrados.
- Se não encontrar pacientes, retorne [].

AGORA EXTRAIA DO TEXTO ABAIXO:

${conteudoFinal}
`.trim();

// =======================================================
// 6) Retorno para o modelo
// =======================================================
return {
  json: {
    contents: [
      {
        role: "user",
        parts: [
          {
            text: prompt
          }
        ]
      }
    ]
  }
};

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function palavrasDoNome(nome) {
  return normalizarTexto(nome)
    .split(" ")
    .filter(p => p.length >= 2);
}

// Conta palavras iguais SOMENTE na mesma posição/sequência
function contarPalavrasIguaisNaSequencia(nome1, nome2) {
  const palavras1 = palavrasDoNome(nome1);
  const palavras2 = palavrasDoNome(nome2);

  let iguaisNaSequencia = 0;
  const menorTamanho = Math.min(palavras1.length, palavras2.length);

  for (let i = 0; i < menorTamanho; i++) {
    if (palavras1[i] === palavras2[i]) {
      iguaisNaSequencia++;
    } else {
      break;
    }
  }

  return iguaisNaSequencia;
}

function garantirArray(valor) {
  if (!valor) return [];

  if (Array.isArray(valor)) return valor;

  if (typeof valor === "string") {
    return valor
      .split(/,|;|\n/)
      .map(v => v.trim())
      .filter(v => v);
  }

  return [valor];
}

const posto = $input.first().json.posto || "";
const data = $input.first().json.data || "";

const input1 = $items("converter resposta para json1").map(item => item.json);
const input2 = $items("converter resposta para json").map(item => item.json);

const resultado = [];

for (const item1 of input1) {
  const pacienteInput1 = item1.PACIENTE || "";
  const examesInput1 = garantirArray(item1.EXAMES);

  let melhorMatch = null;
  let maiorQtdPalavrasIguais = 0;

  for (const item2 of input2) {
    const pacienteInput2 = item2.PACIENTE || "";

    const qtdPalavrasIguais = contarPalavrasIguaisNaSequencia(
      pacienteInput1,
      pacienteInput2
    );

    if (qtdPalavrasIguais > maiorQtdPalavrasIguais) {
      maiorQtdPalavrasIguais = qtdPalavrasIguais;
      melhorMatch = item2;
    }
  }

  const matchPaciente = Boolean(melhorMatch && maiorQtdPalavrasIguais >= 3);

  const pacienteInput2Encontrado = matchPaciente
    ? melhorMatch.PACIENTE || ""
    : "";

  const examesInput2 = matchPaciente
    ? garantirArray(melhorMatch.EXAMES)
    : [];

  const examesInput1Norm = examesInput1.map(normalizarTexto);
  const examesInput2Norm = examesInput2.map(normalizarTexto);

  const examesFaltando = examesInput1.filter(exame =>
    !examesInput2Norm.includes(normalizarTexto(exame))
  );

  const examesExtras = examesInput2.filter(exame =>
    !examesInput1Norm.includes(normalizarTexto(exame))
  );

  const matchExames =
    Boolean(matchPaciente) &&
    examesFaltando.length === 0 &&
    examesExtras.length === 0;

  resultado.push({
    json: {
      posto,
      data,

      PACIENTE_INPUT1: pacienteInput1,
      PACIENTE_INPUT2: pacienteInput2Encontrado,

      matchPaciente,
      palavrasIguaisPaciente: maiorQtdPalavrasIguais,

      matchExames,

      quantidadeExamesInput1: examesInput1.length,
      quantidadeExamesInput2: examesInput2.length,

      examesInput1,
      examesInput2,

      examesFaltandoNoInput2: examesFaltando,
      examesExtrasNoInput2: examesExtras,

      erro: !matchExames,

      mensagem: matchExames
        ? "Paciente e exames estão exatamente iguais"
        : matchPaciente
          ? "Paciente encontrado, mas há divergência entre os exames"
          : "Paciente não encontrado com pelo menos 3 palavras iguais na mesma sequência"
    }
  });
}

return resultado;

